mapper.insert:
INSERT INTO network_artifact (
  artifact_id, task_id, artifact_type, version, stage, status, payload_type,
  payload_json, payload_summary, trace_refs_json, created_by, create_time
) VALUES (
  #{artifactId}, #{taskId}, #{artifactType}, #{version}, #{stage}, #{status}, #{payloadType},
  #{payloadJson}, #{payloadSummary}, #{traceRefsJson}, #{createdBy}, #{createTime}
)

mapper.update:
UPDATE network_artifact
SET status = 'SUPERSEDED'
WHERE task_id = #{taskId}
  AND artifact_type = #{artifactType}
  AND artifact_id <> #{artifactId}
  AND status <> 'SUPERSEDED'

mapper.select:
SELECT artifact_id, task_id, artifact_type, version, stage, status, payload_type,
       payload_json, payload_summary, trace_refs_json, created_by, create_time
FROM network_artifact
WHERE task_id = #{taskId}
  AND artifact_type = #{artifactType}
  AND version = #{version}

SELECT artifact_id, task_id, artifact_type, version, stage, status, payload_type,
       payload_json, payload_summary, trace_refs_json, created_by, create_time
FROM network_artifact
WHERE task_id = #{taskId}
  AND artifact_type = #{artifactType}
ORDER BY version ASC

SELECT MAX(version)
FROM network_artifact
WHERE task_id = #{taskId}
  AND artifact_type = #{artifactType}
